import java.util.*;

public class Solution {
    public static String[] solve(String s) {
        int n = s.length();
        long mod1 = 1000000007, mod2 = 1000000009;
        long base1 = 131, base2 = 137;

        long[] pre1 = new long[n+1];
        long[] pre2 = new long[n+1];
        long[] pow1 = new long[n+1];
        long[] pow2 = new long[n+1];

        pre1[0] = 0;
        pre2[0] = 0;
        pow1[0] = 1;
        pow2[0] = 1;

        for (int i = 1; i <= n; i++) {
            pre1[i] = (pre1[i-1] * base1 + s.charAt(i-1)) % mod1;
            if (pre1[i] < 0) pre1[i] += mod1;
            pre2[i] = (pre2[i-1] * base2 + s.charAt(i-1)) % mod2;
            if (pre2[i] < 0) pre2[i] += mod2;
            pow1[i] = (pow1[i-1] * base1) % mod1;
            pow2[i] = (pow2[i-1] * base2) % mod2;
        }

        List<String> res = new ArrayList<>();
        Set<Long> seen = new HashSet<>();
        int start = 0;
        for (int i = 0; i < n; i++) {
            int len = i - start + 1;
            long hash1 = (pre1[i+1] - (pre1[start] * pow1[len]) % mod1) % mod1;
            if (hash1 < 0) hash1 += mod1;
            long hash2 = (pre2[i+1] - (pre2[start] * pow2[len]) % mod2) % mod2;
            if (hash2 < 0) hash2 += mod2;
            long combined = hash1 * (mod2 + 1) + hash2;

            if (!seen.contains(combined)) {
                String seg = s.substring(start, i+1);
                res.add(seg);
                seen.add(combined);
                start = i+1;
            }
        }

        return res.toArray(new String[0]);
    }
}
```

